{
  "pattern": {
    "summary": "Preserve nsw when InstCombine reassociates a multiplication tree and folds/reorders a constant subexpression, provided the replacement constant multiplication is itself signed-overflow-free.",
    "match": {
      "root": "A mul with nsw whose operand is another mul that also has nsw, forming a tree equivalent to (X * C1) * C2, (C1 * X) * C2, C2 * (X * C1), or C2 * (C1 * X).",
      "operands": [
        "One side of the tree is a non-constant value expression X.",
        "The other two leaves are ConstantInt values C1 and C2."
      ],
      "flags": [
        "The original overflowing binary operators participating in the reassociation must be mul instructions with hasNoSignedWrap().",
        "nuw may be present or absent; it is not required for the nsw preservation rule."
      ]
    },
    "rewrite": {
      "canonical_form": "Reassociate to X * (C1 * C2) and fold the constants.",
      "result": "Create a replacement mul using the folded constant K = C1 * C2. Preserve nsw on the new mul iff signed multiplication of C1 and C2 does not overflow in the result type.",
      "examples": [
        "(mul nsw (mul nsw X, 3), 2) -> mul nsw X, 6",
        "(mul nsw 2, (mul nsw X, -5)) -> mul nsw X, -10"
      ]
    },
    "preconditions": [
      "Both original muls in the reassociated path must have nsw; otherwise InstCombine must not infer nsw on the replacement.",
      "C1 and C2 must be ConstantInt operands in the reassociated constant subexpression.",
      "The folded constant operation C1 * C2 must be provably signed-overflow-free in the destination bitwidth, e.g. via APInt::smul_ov()."
    ],
    "notes": [
      "This is the multiplication analogue of existing maintainNoSignedWrap logic for add/sub constant reassociation.",
      "The key missed optimization is not merely reassociation, but retaining nsw on the newly created mul after the transform.",
      "The transformation should apply across commuted operand orders and nested constant placement patterns."
    ]
  },
